using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Pool de projécteis (Tarefa #22 — melhoria de performance): reutiliza
/// GameObjects de <see cref="ProjectileController"/> em vez de
/// Instantiate/Destroy a cada tiro de <see cref="EnemyAttackController.SpawnProjectile"/>.
///
/// Singleton auto-fallback (mesmo padrão de PlayerProgress/ChallengeManager —
/// ver PlayerProgress.cs "GameBootstrap e singletons"): não precisa de
/// nenhuma configuração no Inspector, basta existir na cena (ou é criado
/// automaticamente antes da primeira cena carregar).
///
/// Cada <see cref="ProjectileData"/> (ou, se definir um "prefab" próprio, esse
/// prefab) tem a sua própria fila de objectos inactivos — diferentes
/// projécteis nunca se misturam, mesmo com sprites/configurações diferentes.
/// </summary>
public class ProjectilePool : MonoBehaviour
{
    public static ProjectilePool Instance { get; private set; }

    /// <summary>Marca instâncias criadas automaticamente por <see cref="EnsureExists"/> (ver PlayerProgress.cs).</summary>
    private bool isAutoFallback;

    private readonly Dictionary<Object, Queue<ProjectileController>> pools = new Dictionary<Object, Queue<ProjectileController>>();
    private Transform poolRoot;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(ProjectilePool) + " (Fallback)");
        var instance = go.AddComponent<ProjectilePool>();
        instance.isAutoFallback = true;
    }

    /// <summary>
    /// Devolve um <see cref="ProjectileController"/> pronto para
    /// <see cref="ProjectileController.Activate"/>, posicionado/rodado em
    /// "position"/"rotation": reutiliza um objecto inactivo da fila de "data"
    /// se existir, senão cria um novo (a partir de "data.prefab", ou de
    /// <see cref="ProjectileController.CreateDefaultProjectileObject"/> se
    /// "data" não tiver prefab).
    /// </summary>
    public ProjectileController Get(ProjectileData data, Vector3 position, Quaternion rotation)
    {
        Object key = data.prefab != null ? (Object)data.prefab : (Object)data;

        if (pools.TryGetValue(key, out var queue))
        {
            while (queue.Count > 0)
            {
                var proj = queue.Dequeue();
                if (proj == null) continue; // destruído externamente (ex: troca de cena)

                proj.transform.SetParent(null);
                proj.transform.SetPositionAndRotation(position, rotation);
                proj.gameObject.SetActive(true);
                return proj;
            }
        }

        GameObject go = data.prefab != null
            ? Instantiate(data.prefab, position, rotation)
            : ProjectileController.CreateDefaultProjectileObject(data, position);

        var newProj = go.GetComponent<ProjectileController>();
        if (newProj == null) newProj = go.AddComponent<ProjectileController>();

        newProj.PoolKey = key;
        return newProj;
    }

    /// <summary>
    /// Desactiva "proj" e devolve-o à fila correspondente à sua
    /// <see cref="ProjectileController.PoolKey"/>, para reutilização futura por
    /// <see cref="Get"/>.
    /// </summary>
    public void Release(ProjectileController proj)
    {
        if (proj == null) return;

        proj.gameObject.SetActive(false);

        if (poolRoot == null)
        {
            var rootGo = new GameObject("Projectiles (Pool)");
            rootGo.transform.SetParent(transform);
            poolRoot = rootGo.transform;
        }

        proj.transform.SetParent(poolRoot);

        if (!pools.TryGetValue(proj.PoolKey, out var queue))
        {
            queue = new Queue<ProjectileController>();
            pools[proj.PoolKey] = queue;
        }

        queue.Enqueue(proj);
    }
}
